import json
import math
import os
import struct
from collections import Counter


def sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def mag(v):
    return math.sqrt(dot(v, v))


def normalize(v):
    m = mag(v)
    if m == 0:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def is_ascii_stl(path):
    with open(path, 'rb') as f:
        data = f.read()
    if len(data) < 6:
        return False
    try:
        text = data.decode('utf-8')
    except UnicodeDecodeError:
        return False
    stripped = text.lstrip()
    return stripped.startswith('solid') and 'facet normal' in text and 'endsolid' in text


def parse_ascii(path):
    triangles = []
    with open(path, 'r', errors='replace') as f:
        lines = f.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            if len(parts) < 5:
                i += 1
                continue
            try:
                n = (float(parts[2]), float(parts[3]), float(parts[4]))
            except ValueError:
                i += 1
                continue
            i += 1
            while i < len(lines) and lines[i].strip() == '':
                i += 1
            if i >= len(lines) or lines[i].strip() != 'outer loop':
                continue
            i += 1
            verts = []
            for _ in range(3):
                if i >= len(lines):
                    break
                vp = lines[i].strip().split()
                if len(vp) >= 4 and vp[0] == 'vertex':
                    try:
                        verts.append((float(vp[1]), float(vp[2]), float(vp[3])))
                    except ValueError:
                        pass
                i += 1
            triangles.append((n, verts))
        else:
            i += 1
    return [(n, v) for n, v in triangles if len(v) == 3]


def parse_binary(path):
    triangles = []
    with open(path, 'rb') as f:
        header = f.read(80)
        count_bytes = f.read(4)
        if len(count_bytes) != 4:
            return []
        count = struct.unpack('<I', count_bytes)[0]
        for _ in range(count):
            rec = f.read(50)
            if len(rec) != 50:
                break
            vals = struct.unpack('<12fH', rec)
            n = (vals[0], vals[1], vals[2])
            v1 = (vals[3], vals[4], vals[5])
            v2 = (vals[6], vals[7], vals[8])
            v3 = (vals[9], vals[10], vals[11])
            triangles.append((n, [v1, v2, v3]))
    return triangles


def validate(path):
    triangles = parse_ascii(path) if is_ascii_stl(path) else parse_binary(path)
    if not triangles:
        return False, 'no_valid_faces'

    edge_counts = Counter()
    nonzero_count = 0
    inverted = False
    degenerate = False

    for declared, verts in triangles:
        v1, v2, v3 = verts
        c = cross(sub(v2, v1), sub(v3, v1))
        cm = mag(c)
        if cm <= 1e-12:
            degenerate = True
        else:
            nonzero_count += 1
            dn = normalize(declared)
            cn = normalize(c)
            dm = mag(declared)
            if dm > 1e-12 and dot(dn, cn) < -0.999:
                inverted = True
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for i in range(3):
            e = tuple(sorted((rounded[i], rounded[(i + 1) % 3])))
            edge_counts[e] += 1

    if degenerate:
        return False, 'degenerate_triangles'
    if any(c == 1 for c in edge_counts.values()):
        return False, 'open_edges'
    if any(c > 2 for c in edge_counts.values()):
        return False, 'non_manifold_edges'
    if inverted:
        return False, 'inverted_normals'
    if nonzero_count == 0:
        return False, 'degenerate_triangles'
    return True, None


def main():
    results = []
    for i in range(1, 51):
        name = f'supplier_{i:03d}.stl'
        valid, reason = validate(name)
        entry = {'file': name, 'valid': valid}
        if not valid:
            entry['reason'] = reason
        results.append(entry)
    with open('validation_report.json', 'w') as f:
        json.dump({'results': results}, f, separators=(',', ':'))
    print(json.dumps({'results': results}, indent=2))


if __name__ == '__main__':
    main()

